#include <vector>
using namespace std;

void dfs(int n, string& cur) {
    if ((int)cur.size() == n) {
        cout << cur << '\n';
        return;
    }
    for (char ch = 'a'; ch <= 'c'; ++ch) {
        cur.push_back(ch);
        dfs(n, cur);
        cur.pop_back();
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    string cur;
    dfs(n, cur);
    return 0;
}

