#include <algorithm>
#include <cmath>
#include <iostream>
#include <map>
#include <numeric>
#include <set>
#include <string>
#include <tuple>
#include <utility>
#include <vector>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, c;
    cin >> n >> c;
    vector<vector<pair<int, int>>> byChannel(c + 1);
    int maxTime = 0;
    for (int i = 0; i < n; ++i) {
        int s, t, ch;
        cin >> s >> t >> ch;
        byChannel[ch].push_back({s, t});
        maxTime = max(maxTime, t);
    }

    vector<int> diff(maxTime * 2 + 5, 0);
    for (int ch = 1; ch <= c; ++ch) {
        auto& v = byChannel[ch];
        sort(v.begin(), v.end());
        int l = -1, r = -1;
        for (const auto& seg : v) {
            if (l == -1) {
                l = seg.first;
                r = seg.second;
            } else if (seg.first <= r) {
                r = max(r, seg.second);
            } else {
                diff[2 * l - 1]++;
                diff[2 * r]--;
                l = seg.first;
                r = seg.second;
            }
        }
        if (l != -1) {
            diff[2 * l - 1]++;
            diff[2 * r]--;
        }
    }

    int cur = 0, ans = 0;
    for (int x : diff) {
        cur += x;
        ans = max(ans, cur);
    }
    cout << ans << '\n';
    return 0;
}

